import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, Card, Progress, icon } from 'decantr/components';

code.example:
function ContentUploader({ onUpload, accept = '*', multiple = true }) {
  const { div, input, span, p, img, video } = tags;
  const [files, setFiles] = createSignal([]);
  const [dragOver, setDragOver] = createSignal(false);

  const handleDrop = (e) => {
    e.preventDefault();
    setDragOver(false);
    const dropped = Array.from(e.dataTransfer.files);
    setFiles([...files(), ...dropped.map(f => ({ file: f, progress: 0, id: crypto.randomUUID() }))]);
  };

  const handleFiles = (e) => {
    const selected = Array.from(e.target.files);
    setFiles([...files(), ...selected.map(f => ({ file: f, progress: 0, id: crypto.randomUUID() }))]);
  };

  const removeFile = (id) => setFiles(files().filter(f => f.id !== id));

  const getPreview = (file) => {
    if (file.file.type.startsWith('image/')) return URL.createObjectURL(file.file);
    if (file.file.type.startsWith('video/')) return 'video';
    if (file.file.type.startsWith('audio/')) return 'audio';
    return 'document';
  };

  return div({ class: css('_flex _col _gap4') },
    div({
      class: css(`studio-card _flex _col _center _p8 _r3 _border2 _borderdashed _trans ${dragOver() ? '_borderPrimary _bgPrimary/5' : '_bordermuted'}`),
      ondragover: (e) => { e.preventDefault(); setDragOver(true); },
      ondragleave: () => setDragOver(false),
      ondrop: handleDrop
    },
      icon('upload-cloud', { size: '48', class: css('_fgmuted _mb4') }),
      p({ class: css('_textlg _fontmedium _mb2') }, 'Drag and drop files here'),
      p({ class: css('_fgmuted _mb4') }, 'or'),
      Button({ variant: 'outline', as: 'label' },
        'Browse Files',
        input({ type: 'file', accept, multiple, onchange: handleFiles, class: css('_hidden') })
      )
    ),
    files().length > 0 ? div({ class: css('_grid _gc2 _md:gc3 _gap4') },
      ...files().map(f =>
        Card({ class: css('studio-card _p3 _flex _col _gap2') },
          div({ class: css('_relative _aspect[16/9] _r2 _overflow[hidden] _bgmuted/10') },
            getPreview(f) !== 'video' && getPreview(f) !== 'audio' && getPreview(f) !== 'document'
              ? img({ src: getPreview(f), class: css('_wfull _hfull _objcover') })
              : div({ class: css('_flex _center _hfull') },
                  icon(getPreview(f) === 'video' ? 'video' : getPreview(f) === 'audio' ? 'music' : 'file', { size: '32', class: css('_fgmuted') })
                ),
            Button({
              variant: 'ghost',
              size: 'sm',
              class: css('_absolute _top1 _right1 _bgbg/80'),
              onclick: () => removeFile(f.id)
            }, icon('x', { size: '16' }))
          ),
          span({ class: css('_textsm _truncate') }, f.file.name),
          f.progress > 0 && f.progress < 100
            ? Progress({ value: f.progress, class: css('_h1') })
            : null
        )
      )
    ) : null,
    files().length > 0 ? div({ class: css('_flex _gap2 _jce') },
      Button({ variant: 'ghost', onclick: () => setFiles([]) }, 'Clear All'),
      Button({ variant: 'primary', onclick: () => onUpload?.(files()) },
        icon('upload', { size: '16', class: css('_mr2') }), 'Upload ', files().length, ' Files'
      )
    ) : null
  );
}

