function SingleUploader({ onUpload, accept = 'image/*' }) {
  const { div, input, img, p } = tags;
  const [file, setFile] = createSignal(null);
  const [dragOver, setDragOver] = createSignal(false);

  const handleFile = (f) => setFile({ file: f, preview: URL.createObjectURL(f) });

  return div({ class: css('_flex _col _gap4') },
    div({
      class: css(`studio-card _aspect[16/9] _r3 _overflow[hidden] _border2 _borderdashed _trans ${dragOver() ? '_borderPrimary' : '_bordermuted'}`),
      ondragover: (e) => { e.preventDefault(); setDragOver(true); },
      ondragleave: () => setDragOver(false),
      ondrop: (e) => { e.preventDefault(); setDragOver(false); handleFile(e.dataTransfer.files[0]); }
    },
      file()
        ? img({ src: file().preview, class: css('_wfull _hfull _objcover') })
        : div({ class: css('_flex _col _center _hfull') },
            icon('image', { size: '48', class: css('_fgmuted _mb4') }),
            p({ class: css('_fgmuted') }, 'Drop image here or click to browse')
          )
    ),
    div({ class: css('_flex _gap2 _jcc') },
      Button({ variant: 'outline', as: 'label' },
        file() ? 'Replace' : 'Choose File',
        input({ type: 'file', accept, onchange: (e) => handleFile(e.target.files[0]), class: css('_hidden') })
      ),
      file() ? Button({ variant: 'ghost', onclick: () => setFile(null) }, 'Remove') : null
    )
  );
}

