function AudioUploader({ onUpload }) {
  const { div, input, audio, p, span } = tags;
  const [file, setFile] = createSignal(null);

  return div({ class: css('_flex _col _gap4') },
    file() ? Card({ class: css('studio-card _p4') },
      div({ class: css('_flex _aic _gap4') },
        div({ class: css('_w12 _h12 _r2 _bgPrimary/10 _flex _center') },
          icon('music', { class: css('_fgPrimary') })
        ),
        div({ class: css('_flex1') },
          p({ class: css('_fontmedium') }, file().name),
          span({ class: css('_textsm _fgmuted') }, (file().size / 1024 / 1024).toFixed(2), ' MB')
        ),
        Button({ variant: 'ghost', size: 'sm', onclick: () => setFile(null) }, icon('x'))
      ),
      audio({ src: URL.createObjectURL(file()), controls: true, class: css('_wfull _mt4') })
    ) : div({
      class: css('studio-card _flex _col _center _p8 _r3 _border2 _borderdashed _bordermuted')
    },
      icon('music', { size: '48', class: css('_fgmuted _mb4') }),
      p({ class: css('_fgmuted _mb4') }, 'Drop audio file here'),
      Button({ variant: 'outline', as: 'label' },
        'Choose Audio',
        input({ type: 'file', accept: 'audio/*', onchange: (e) => setFile(e.target.files[0]), class: css('_hidden') })
      )
    )
  );
}

